product-info:
Here is the complete `.liquid` section file for `product-info`:

```liquid
{%- comment -%}
  Section: product-info
  Type: product_info
  Generated by: Section Conversion Agent v1.2
  Dawn version: 15.0
  NOTE: The competitor HTML contained only a Kaching Bundles app script tag.
        This section is reconstructed from content_signals: benefits list, join statement, clinicians' choice badge.
  IMAGE UPLOAD REQUIRED: Merchants must upload a badge image via Theme Editor for the "Clinicians' Choice Badge" setting.
{%- endcomment -%}

{%- liquid
  assign selected_variant = product.selected_or_first_available_variant
  assign product_form_id = 'product-form-' | append: section.id
-%}

<section
  id="ProductInfo-{{ section.id }}"
  class="section-{{ section.id }} product-info color-{{ section.settings.color_scheme }} gradient"
>
  <div class="page-width">
    <div class="product-info__grid grid grid--2-col-tablet">
      {%- comment -%} LEFT COLUMN: Product Media {%- endcomment -%}
      <div class="product-info__media grid__item">
        {%- if product.featured_image != blank -%}
          {{
            product.featured_image
            | image_url: width: 1500
            | image_tag:
              widths: '375, 550, 750, 1100, 1500',
              sizes: '(min-width: 750px) 50vw, 100vw',
              class: 'product-info__featured-image',
              loading: 'eager',
              alt: product.featured_image.alt | escape
          }}
        {%- else -%}
          {{ 'product-1' | placeholder_svg_tag: 'placeholder-svg' }}
        {%- endif -%}

        {%- if product.media.size > 1 -%}
          <ul class="product-info__thumbnails grid grid--4-col-desktop" role="list">
            {%- for media in product.media -%}
              <li class="grid__item">
                {%- case media.media_type -%}
                  {%- when 'image' -%}
                    {{
                      media
                      | image_url: width: 375
                      | image_tag:
                        widths: '150, 250, 375',
                        sizes: '(min-width: 750px) 10vw, 25vw',
                        loading: 'lazy',
                        class: 'product-info__thumbnail',
                        alt: media.alt | escape
                    }}
                  {%- when 'video' -%}
                    {{ media | video_tag: autoplay: false, loop: false, controls: true }}
                  {%- when 'external_video' -%}
                    {{ media | external_video_tag }}
                  {%- when 'model' -%}
                    {{ media | model_viewer_tag }}
                {%- endcase -%}
              </li>
            {%- endfor -%}
          </ul>
        {%- endif -%}
      </div>

      {%- comment -%} RIGHT COLUMN: Product Details {%- endcomment -%}
      <div class="product-info__details grid__item">
        {%- comment -%} Clinicians' Choice Badge {%- endcomment -%}
        {%- if section.settings.badge_text != blank -%}
          <div class="product-info__badge">
            {%- if section.settings.badge_image != blank -%}
              {{
                section.settings.badge_image
                | image_url: width: 80
                | image_tag:
                  loading: 'eager',
                  class: 'product-info__badge-icon',
                  alt: section.settings.badge_image.alt | escape
              }}
            {%- endif -%}
            <span class="product-info__badge-text">{{ section.settings.badge_text | escape }}</span>
          </div>
        {%- endif -%}

        {%- comment -%} Product Title {%- endcomment -%}
        <h1 class="product-info__title">{{ product.title }}</h1>

        {%- comment -%} Vendor {%- endcomment -%}
        {%- if section.settings.show_vendor and product.vendor != blank -%}
          <p class="product-info__vendor">{{ product.vendor }}</p>
        {%- endif -%}

        {%- comment -%} Price {%- endcomment -%}
        <div class="product-info__price price {% if product.compare_at_price > product.price %}price--on-sale{% endif %}">
          <span class="price__current" aria-label="{{ 'products.product.price.regular_price' | t }}">
            {{ product.price | money }}
          </span>
          {%- if product.compare_at_price > product.price -%}
            <s class="price__compare" aria-label="{{ 'products.product.price.regular_price' | t }}">
              {{ product.compare_at_price | money }}
            </s>
          {%- endif -%}
        </div>

        {%- comment -%} Benefits List {%- endcomment -%}
        {%- assign benefit_blocks = section.blocks | where: 'type', 'benefit_item' -%}
        {%- if benefit_blocks.size > 0 -%}
          <ul class="product-info__benefits" role="list">
            {%- for block in section.blocks -%}
              {%- if block.type == 'benefit_item' -%}
                <li class="product-info__benefit-item" {{ block.shopify_attributes }}>
                  <span class="product-info__benefit-icon" aria-hidden="true">
                    {%- if block.settings.icon != blank -%}
                      {{
                        block.settings.icon
                        | image_url: width: 40
                        | image_tag:
                          loading: 'lazy',
                          alt: ''
                      }}
                    {%- else -%}
                      <svg width="20" height="20" viewBox="0 0 20 20" fill="none" aria-hidden="true">
                        <path d="M16.667 5L7.5 14.167 3.333 10" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
                      </svg>
                    {%- endif -%}
                  </span>
                  <span class="product-info__benefit-text">{{ block.settings.text | escape }}</span>
                </li>
              {%- endif -%}
            {%- endfor -%}
          </ul>
        {%- endif -%}

        {%- comment -%} Variant Selectors {%- endcomment -%}
        {%- if product.has_only_default_variant == false -%}
          <div class="product-info__variants">
            {%- for option in product.options_with_values -%}
              <fieldset class="product-form__input product-form__input--pill">
                <legend class="form__label">{{ option.name }}</legend>
                {%- for value in option.values -%}
                  <input
                    type="radio"
                    id="Option-{{ section.id }}-{{ option.position }}-{{ forloop.index0 }}"
                    name="{{ option.name }}"
                    value="{{ value | escape }}"
                    form="{{ product_form_id }}"
                    {% if option.selected_value == value %}checked{% endif %}
                  >
                  <label for="Option-{{ section.id }}-{{ option.position }}-{{ forloop.index0 }}">
                    {{ value }}
                  </label>
                {%- endfor -%}
              </fieldset>
            {%- endfor -%}
          </div>
        {%- endif -%}

        {%- comment -%} Add to Cart Form {%- endcomment -%}
        <div class="product-info__form">
          {%- form 'product', product, id: product_form_id, novalidate: 'novalidate' -%}
            <input type="hidden" name="id" value="{{ selected_variant.id }}">

            <div class="product-info__quantity">
              <label for="Quantity-{{ section.id }}" class="form__label">
                {{ 'products.product.quantity.label' | t }}
              </label>
              {% render 'quantity-input', id: section.id %}
            </div>

            <button
              type="submit"
              name="add"
              class="button button--primary button--full-width product-info__submit"
              {% if selected_variant.available == false %}disabled{% endif %}
            >
              {%- if selected_variant.available -%}
                {{ 'products.product.add_to_cart' | t }}
              {%- else -%}
                {{ 'products.product.sold_out' | t }}
              {%- endif -%}
            </button>

            <div
              id="CartErrors-{{ section.id }}"
              role="alert"
              aria-live="polite"
              aria-atomic="true"
              class="product-info__error-message"
            ></div>
          {%- endform -%}
        </div>

        {%- comment -%} Join Statement {%- endcomment -%}
        {%- if section.settings.join_statement != blank -%}
          <p class="product-info__join-statement">{{ section.settings.join_statement | escape }}</p>
        {%- endif -%}

        {%- comment -%} Description {%- endcomment -%}
        {%- if product.description != blank -%}
          <div class="product-info__description rte">
            {{ product.description }}
          </div>
        {%- endif -%}

        {%- comment -%} Accordion Blocks (e.g. Details, Shipping, etc.) {%- endcomment -%}
        {%- for block in section.blocks -%}
          {%- if block.type == 'accordion_item' -%}
            <details class="product-info__accordion accordion" id="Accordion-{{ section.id }}-{{ forloop.index }}" {{ block.shopify_attributes }}>
              <summary class="accordion__title">
                {{ block.settings.heading | escape }}
                {% render 'icon-caret' %}
              </summary>
              <div class="accordion__content rte">
                {{ block.settings.content }}
              </div>
            </details>
          {%- endif -%}
        {%- endfor -%}
      </div>
    </div>
  </div>
</section>

{% style %}
  .section-{{ section.id }} {
    padding-top: {{ section.settings.padding_top }}px;
    padding-bottom: {{ section.settings.padding_bottom }}px;
  }

  .section-{{ section.id }} .product-info__grid {
    gap: 2rem;
    align-items: flex-start;
  }

  .section-{{ section.id }} .product-info__featured-image {
    width: 100%;
    height: auto;
    border-radius: 0.4rem;
  }

  .section-{{ section.id }} .product-info__thumbnails {
    list-style: none;
    padding: 0;
    margin: 1rem 0 0;
    gap: 0.8rem;
  }

  .section-{{ section.id }} .product-info__thumbnail {
    width: 100%;
    height: auto;
    border-radius: 0.2rem;
    cursor: pointer;
    border: 1px solid rgba(var(--color-foreground), 0.1);
  }

  .section-{{ section.id }} .product-info__badge {
    display: inline-flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.4rem 1rem;
    border: 1px solid rgba(var(--color-foreground), 0.15);
    border-radius: 2rem;
    margin-bottom: 1.2rem;
    font-size: 1.2rem;
    font-family: var(--font-body-family);
    text-transform: uppercase;
    letter-spacing: 0.08em;
  }

  .section-{{ section.id }} .product-info__badge-icon {
    width: 2.4rem;
    height: auto;
  }

  .section-{{ section.id }} .product-info__title {
    font-family: var(--font-heading-family);
    font-weight: var(--font-heading-weight);
    margin: 0 0 0.8rem;
  }

  .section-{{ section.id }} .product-info__vendor {
    font-size: 1.3rem;
    margin: 0 0 1rem;
    color: rgba(var(--color-foreground), 0.7);
    text-transform: uppercase;
    letter-spacing: 0.06em;
  }

  .section-{{ section.id }} .product-info__price {
    margin-bottom: 1.6rem;
  }

  .section-{{ section.id }} .price__current {
    font-size: 1.8rem;
    font-weight: 600;
  }

  .section-{{ section.id }} .price--on-sale .price__current {
    color: rgb(var(--color-foreground));
  }

  .section-{{ section.id }} .price__compare {
    font-size: 1.4rem;
    color: rgba(var(--color-foreground), 0.55);
    margin-left: 0.6rem;
  }

  .section-{{ section.id }} .product-info__benefits {
    list-style: none;
    padding: 0;
    margin: 0 0 2rem;
    display: flex;
    flex-direction: column;
    gap: 0.8rem;
  }

  .section-{{ section.id }} .product-info__benefit-item {
    display: flex;
    align-items: center;
    gap: 0.8rem;
    font-size: 1.4rem;
    font-family: var(--font-body-family);
  }

  .section-{{ section.id }} .product-info__benefit-icon svg {
    color: rgb(var(--color-foreground));
  }

  .section-{{ section.id }} .product-info__variants {
    margin-bottom: 1.6rem;
  }

  .section-{{ section.id }} .product-form__input--pill {
    display: flex;
    flex-wrap: wrap;
    gap: 0.8rem;
    border: none;
    padding: 0;
    margin-bottom: 1.2rem;
  }

  .section-{{ section.id }} .product-form__input--pill legend {
    margin-bottom: 0.6rem;
    width: 100%;
    font-size: 1.3rem;
    font-weight: 600;
  }

  .section-{{ section.id }} .product-form__input--pill input[type="radio"] {
    position: absolute;
    width: 1px;
    height: 1px;
    overflow: hidden;
    clip: rect(0 0 0 0);
  }

  .section-{{ section.id }} .product-form__input--pill label {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0.6rem 1.6rem;
    border: 1px solid rgba(var(--color-foreground), 0.2);
    border-radius: 0.4rem;
    cursor: pointer;
    font-size: 1.3rem;
    min-width: 4rem;
    text-align: center;
  }

  .section-{{ section.id }} .product-form__input--pill input[type="radio"]:checked + label {
    border-color: rgb(var(--color-foreground));
    background: rgb(var(--color-foreground));
    color: rgb(var(--color-background));
  }

  .section-{{ section.id }} .product-form__input--pill input[type="radio"]:focus-visible + label {
    outline: 0.3rem solid rgba(var(--color-foreground), 0.5);
    outline-offset: 0.3rem;
  }

  .section-{{ section.id }} .product-info__quantity {
    margin-bottom: 1.2rem;
  }

  .section-{{ section.id }} .product-info__submit {
    margin-bottom: 1rem;
  }

  .section-{{ section.id }} .product-info__error-message:empty {
    display: none;
  }

  .section-{{ section.id }} .product-info__error-message {
    color: rgb(var(--color-foreground));
    font-size: 1.3rem;
    margin-bottom: 1rem;
  }

  .section-{{ section.id }} .product-info__join-statement {
    font-size: 1.3rem;
    color: rgba(var(--color-foreground), 0.7);
    text-align: center;
    margin: 0.8rem 0 2rem;
    font-style: italic;
  }

  .section-{{ section.id }} .product-info__description {
    margin-top: 1.6rem;
    font-size: 1.4rem;
    line-height: 1.7;
  }

  .section-{{ section.id }} .product-info__accordion {
    border-top: 1px solid rgba(var(--color-foreground), 0.1);
    padding: 1.2rem 0;
  }

  .section-{{ section.id }} .accordion__title {
    display: flex;
    justify-content: space-between;
    align-items: center;
    cursor: pointer;
    font-size: 1.4rem;
    font-weight: 600;
    list-style: none;
    font-family: var(--font-body-family);
  }

  .section-{{ section.id }} .accordion__title::-webkit-details-marker {
    display: none;
  }

  .section-{{ section.id }} .accordion__content {
    padding-top: 1rem;
    font-size: 1.4rem;
    line-height: 1.7;
  }

  @media (min-width: 750px) {
    .section-{{ section.id }} .product-info__grid {
      gap: 4rem;
    }

    .section-{{ section.id }} .product-info__title {
      font-size: 3.2rem;
    }

    .section-{{ section.id }} .price__current {
      font-size: 2.2rem;
    }
  }
{% endstyle %}

